// src/components/Home.js
import React from 'react';
import "../styles/Home.css";

const Home = () => {
  return (
    <section className="hero">
      <div className="overlay"></div>
      <div className="hero-content">
        <p className="tagline">Need Help With School or College Projects?</p>
        <h1>
          <span>Don't Worry,</span>{" "}
          <span className="highlight">ProjectDuniya</span>{" "}
          <span>Is Here To Help!</span>
        </h1>
        <p className="description">
          From school models to final year engineering and BCA projects, we simplify it all.
          Get customized, deadline-friendly project support that's tailored to your academic needs.
          Fast delivery, affordable prices, and full guidance — all in one place.
        </p>
        <div className="hero-buttons">
          <a href="#" className="btn primary">Explore Services</a>
          <a href="#" className="btn secondary">Contact Us</a>
        </div>
      </div>
    </section>
  );
};

export default Home;
